router.post('/vulnerable/save', (req, res) => {
  const userId = parseInt(req.headers['x-user-id']) || 1;
  const { q } = req.body;
  // Safe — parameterized. Looks correct.
  db.prepare('INSERT OR REPLACE INTO saved_searches (user_id, query) VALUES (?, ?)')
    .run(userId, q);
  res.json({ saved: true });
});

router.get('/vulnerable/run', (req, res) => {
  const userId = parseInt(req.headers['x-user-id']) || 1;
  const saved = db.prepare(
    'SELECT query FROM saved_searches WHERE user_id = ?'
  ).get(userId);

  // ⚠ 'saved.query' came from the database — feels trusted.
  // But the user wrote it. This is second-order injection.
  const results = db.prepare(
    `SELECT id, name, price FROM products WHERE name LIKE '%${saved.query}%'`
  ).all();
  res.json({ results });
});

